local BV_U32 = 4294967296
local BV_BAND, BV_BOR, BV_BXOR, BV_BNOT = bit32.band, bit32.bor, bit32.bxor, bit32.bnot
local BV_RSHIFT, BV_RROTATE, BV_LROTATE = bit32.rshift, bit32.rrotate, bit32.lrotate
local BV_SHA_K = {
