    local function normalizeDeviceIdentity(value)
        if TYPE(value) ~= 'string' then return nil end
        value = value:match('^%s*(.-)%s*$')
        if #value < 8 or #value > 512 then return nil end
        return value
    end

    local function tryDeviceIdentity(candidate, owner)
        if TYPE(candidate) ~= 'function' then return nil end
        local ok, value = PCALL(candidate)
        if not ok and owner ~= nil then ok, value = PCALL(candidate, owner) end
        return ok and normalizeDeviceIdentity(value) or nil
    end

    local deviceIdentity = tryDeviceIdentity(environment.gethwid)
        or tryDeviceIdentity(environment.get_hwid)
        or tryDeviceIdentity(
            TYPE(synapse) == 'table' and (synapse.gethwid or synapse.get_hwid) or nil,
            synapse
        )
    if not deviceIdentity then
        local analyticsOk, analytics = PCALL(function()
            return G:GetService('RbxAnalyticsService')
        end)
        if analyticsOk and analytics then
            deviceIdentity = tryDeviceIdentity(analytics.GetClientId, analytics)
        end
    end

    local function tryExecutorName(candidate)
        if TYPE(candidate) ~= 'function' then return nil end
        local ok, value = PCALL(candidate)
        if not ok or TYPE(value) ~= 'string' then return nil end
        value = S_GSUB(value, '%c', ''):match('^%s*(.-)%s*$')
        if #value == 0 then return nil end
        return S_SUB(value, 1, 64)
    end

    local executorName = tryExecutorName(environment.identifyexecutor)
        or tryExecutorName(environment.getexecutorname)

    local function sum(source)
        local hash = 2166136261 % MOD
        for index = 1, #source do
            hash = (hash * 65599 + S_BYTE(source, index)) % MOD
        end
        return hash .. ''
    end

    local function hexByte(value)
        local chars, high = '0123456789abcdef', FLOOR(value / 16)
        return S_SUB(chars, high + 1, high + 1) .. S_SUB(chars, value - high * 16 + 1, value - high * 16 + 1)
    end

    local function hex32(value)
        local out = {}
        value %= 4294967296
        for _ = 1, 4 do
            local quotient = FLOOR(value / 256)
            out[#out + 1] = hexByte(value - quotient * 256)
            value = quotient
        end
        return T_CONCAT(out)
    end

    local function playerScripts()
        local player = G:GetService('Players').LocalPlayer
        return player and (
            player:FindFirstChildOfClass('PlayerScripts')
            or player:FindFirstChild('PlayerScripts')
            or player:WaitForChild('PlayerScripts', 5)
        )
    end

    local function cleanup(registry, name, actors)
        PCALL(function() registry:SetSharedTable(name, nil) end)
        for index = 1, #actors do
            PCALL(function() actors[index]:Destroy() end)
        end
    end

    local function actorRng()
        local registry, parent = G:GetService('SharedTableRegistry'), playerScripts()
        if not registry or not parent then return nil, nil, 'actor_parent_unavailable' end

        local name = 'bv_ar_' .. S_GSUB(httpService:GenerateGUID(false), '%W', '')
        local sharedTable, actors = ST.new(), {}
        local actorCount, laneCount, rounds = 6, 8, 7
        local doneBase, sampleBase = 64, 1024
        sharedTable[0], sharedTable[1], sharedTable[2] = 0, 0, 0
        registry:SetSharedTable(name, sharedTable)

        for id = 1, actorCount do
            local actor, dummy = INST.new('Actor'), INST.new('LocalScript')
            actor.Name, dummy.Name, dummy.Parent, actor.Parent = 'bv_ar' .. id, 'bv_ars' .. id, actor, parent
            actors[id] = actor
            TASK.wait()
            TASK.wait()
            dummy:Destroy()

            local body = "local st=game:GetService('SharedTableRegistry'):GetSharedTable('" .. name .. "')\n"
                .. "local inc=SharedTable.increment\n"
                .. "local wait=task.wait\n"
                .. "local ok,err=pcall(function()\n"
                .. " for round=1," .. rounds .. " do\n"
                .. "  for lane=1," .. laneCount .. " do\n"
                .. "   local order=inc(st,0,1)\n"
                .. "   local base=" .. sampleBase .. "+(lane-1)*4\n"
                .. "   local a=(order*69621+" .. id .. "*48271+round*19349663+lane*1103515245)%2147483647\n"
                .. "   local b=(order*16777619+" .. id .. "*2246822519+round*83492791+lane*668265263)%2147483647\n"
                .. "   local c=(order*1103515245+" .. id .. "*374761393+round*2654435761+lane*3266489917)%2147483647\n"
                .. "   local d=(a+b*3+c*5+order*7+" .. id .. "*11)%2147483647\n"
                .. "   local jitter=0\n"
                .. "   for byteIndex=1,4 do\n"
                .. "    local values={1,1,1,1,1,1,1,1}\n"
                .. "    local p1,p2,p3,p4,p5,p6,p7,p8={},{},{},{},{},{},{},{}\n"
                .. "    values[p1]=a+byteIndex; values[p2]=b+lane; values[p3]=c+round; values[p4]=d+" .. id .. "\n"
                .. "    values[p5]=order+byteIndex; values[p6]=jitter+17; values[p7]=lane+29; values[p8]=round+43\n"
                .. "    values[3]=nil; values[4]=nil; values[5]=nil; values[6]=nil; values[7]=nil; values[p8]=nil\n"
                .. "    local pn={}; values[pn]=byteIndex\n"
                .. "    local length=#values\n"
                .. "    local mixed={}; mixed[p1]=a%65521; mixed[p3]=b%65519; mixed[p5]=c%65517; mixed[pn]=d%65513\n"
                .. "    for _,value in mixed do jitter=(jitter*257+value*263+length*269+byteIndex)%2147483647 end\n"
                .. "   end\n"
                .. "   a=(a+jitter*3+order)%2147483647\n"
                .. "   b=(b+jitter*5+lane)%2147483647\n"
                .. "   c=(c+jitter*7+round)%2147483647\n"
                .. "   d=(d+jitter*11+" .. id .. ")%2147483647\n"
                .. "   if st[base+1]==nil then st[base+1]=1 end\n"
                .. "   if st[base+2]==nil then st[base+2]=1 end\n"
                .. "   if st[base+3]==nil then st[base+3]=1 end\n"
                .. "   if st[base+4]==nil then st[base+4]=1 end\n"
                .. "   inc(st,base+1,a+1); inc(st,base+2,b+1); inc(st,base+3,c+1); inc(st,base+4,d+1)\n"
                .. "  end\n"
                .. "  wait()\n"
                .. " end\n"
                .. " st[" .. (doneBase + id) .. "]=(" .. id .. "*7919+" .. rounds .. "*104729)%2147483647\n"
                .. " inc(st,1,1)\n"
                .. "end)\n"
                .. "if not ok then st['err" .. id .. "']=tostring(err); inc(st,2,1); inc(st,1,1) end\n"

            TASK.defer(function()
                local launched, launchError = PCALL(function() ROA(actor, body) end)
                if not launched then
                    sharedTable['err' .. id] = tostring(launchError)
                    ST.increment(sharedTable, 2, 1)
                    ST.increment(sharedTable, 1, 1)
                end
            end)
        end

        for _ = 1, 180 do
            if sharedTable[1] >= actorCount then break end
            TASK.wait()
        end
        if sharedTable[1] < actorCount then
            cleanup(registry, name, actors)
            return nil, nil, 'actor_rng_timeout'
        end
        if sharedTable[2] ~= 0 then
            local reason = sharedTable.err1 or sharedTable.err2 or sharedTable.err3
                or sharedTable.err4 or sharedTable.err5 or sharedTable.err6
            cleanup(registry, name, actors)
            return nil, nil, 'actor_rng_worker:' .. tostring(reason or 'unknown')
        end

        local gate = 0
        for id = 1, actorCount do
            local done = sharedTable[doneBase + id]
            if not done then cleanup(registry, name, actors); return nil, nil, 'actor_rng_gate' end
            gate = (gate * 257 + done) % MOD
        end

        local output = {}
        for lane = 1, laneCount do
            local base = sampleBase + (lane - 1) * 4
            local a, b = sharedTable[base + 1], sharedTable[base + 2]
            local c, d = sharedTable[base + 3], sharedTable[base + 4]
            if not a or not b or not c or not d then
                cleanup(registry, name, actors)
                return nil, nil, 'actor_rng_lane'
            end
            local word = ((a % 65521) * 69621
                + (b % 65519) * 48271
                + (c % 65517) * 16777619
                + (d % 65513) * 65537
                + (gate % 65511) * 4099
                + lane * 1103515245) % 4294967296
            for _ = 1, 4 do
                local quotient = FLOOR(word / 256)
                output[#output + 1] = hexByte(word - quotient * 256)
                word = quotient
            end
        end

        local rng = T_CONCAT(output)
        local guard = S_GSUB(httpService:GenerateGUID(false), '%W', '')
            .. hex32(gate)
            .. hex32(sharedTable[0] or 0)
        cleanup(registry, name, actors)
        return rng, guard
    end

    local function post(payload, headers)
        local response = REQ({
            Url = 'https://luvit.cc/badvape-api/v1/auth/verify',
            Method = 'POST',
            Headers = headers,
            Body = httpService:JSONEncode(payload)
        })
        if TYPE(response) ~= 'table' then return nil, 'auth_http_response' end
        local status = tonumber(response.StatusCode or response.Status or response.status)
        local body = response.Body or response.body
        if status ~= 200 then return nil, 'auth_http_status_' .. tostring(status or 'unknown') end
        if TYPE(body) ~= 'string' then return nil, 'auth_http_body' end
        local ok, decoded = PCALL(httpService.JSONDecode, httpService, body)
        if not ok or TYPE(decoded) ~= 'table' then return nil, 'auth_http_json' end
        return decoded
    end

    local sessionSlot = '__BV_ACTOR_SESSION'

    local previousSession
    PCALL(function()
        previousSession = environment[sessionSlot]
        environment[sessionSlot] = nil
    end)
    if TYPE(previousSession) == 'function' then PCALL(previousSession) end

    local rng, guard, rngError = actorRng()
    if not rng or not guard then
        rngError = rngError or 'actor_rng_unavailable'
        PRINT('[simpleauth]', rngError)
        WARN('[simpleauth]', rngError)
        return false
    end

    local nonce = httpService:GenerateGUID(false)
    local placeId = tostring(G.PlaceId)
    if TYPE(nonce) ~= 'string' or #nonce < 16 or not placeId:match('^%d+$') then
        PRINT('[simpleauth]', 'auth_request_material')
        return false
    end
    local payload = {
        protocolVersion = 3,
        key = credential,
        nonce = nonce,
        placeId = placeId,
        releaseId = sealedPayload.releaseId,
        rng = rng,
        guard = guard
    }
    payload.check = sum(payload.nonce .. '|' .. payload.rng .. '|' .. payload.guard .. '|' .. payload.releaseId)

    local headers = {
        ['Accept'] = 'application/json',
        ['Content-Type'] = 'application/json'
    }
    if deviceIdentity then headers['X-HWID'] = deviceIdentity end
    if executorName then headers['X-Executor'] = executorName end

    local responseOk, response, responseError = PCALL(post, payload, headers)
    if not responseOk
        or TYPE(response) ~= 'table'
        or response.ok ~= true
        or response.protocolVersion ~= 3
        or response.nonce ~= nonce
        or tostring(response.placeId) ~= placeId
        or response.releaseId ~= sealedPayload.releaseId
        or TYPE(response.salt) ~= 'string'
        or TYPE(response.blob) ~= 'string'
        or TYPE(response.keyCheck) ~= 'string'
        or TYPE(response.wrappedKey) ~= 'string'
        or TYPE(response.wrapTag) ~= 'string' then
        PRINT('[simpleauth]', responseOk and (responseError or 'auth_response_invalid') or 'auth_request_failed')
        return false
    end

    local registry, parent = G:GetService('SharedTableRegistry'), playerScripts()
    if not registry or not parent then return false end

    local baseRuntime
    PCALL(function() baseRuntime = shared and shared.vape end)
    if TYPE(baseRuntime) ~= 'table' or TYPE(baseRuntime.Libraries) ~= 'table' then
        PRINT('[simpleauth]', 'base_runtime_unavailable')
        return false
    end

    local name = 'bv_ap_' .. S_GSUB(httpService:GenerateGUID(false), '%W', '')
    local sharedTable, noiseActors = ST.new(), {}
    sharedTable[0], sharedTable[1], sharedTable[2], sharedTable[3], sharedTable[4] = 0, 0, 0, 0, 0
    sharedTable[16], sharedTable[17], sharedTable[18] = 0, 0, 0
    sharedTable.nonce, sharedTable.placeId = payload.nonce, payload.placeId
    sharedTable.rng, sharedTable.guard, sharedTable.releaseId = payload.rng, payload.guard, payload.releaseId
    sharedTable.salt, sharedTable.blob, sharedTable.keyCheck = response.salt, response.blob, response.keyCheck
    sharedTable.wrappedKey, sharedTable.wrapTag = response.wrappedKey, response.wrapTag
    registry:SetSharedTable(name, sharedTable)

    for id = 1, 3 do
        local actor, dummy = INST.new('Actor'), INST.new('LocalScript')
        actor.Name, dummy.Name, dummy.Parent, actor.Parent = 'bv_apn' .. id, 'bv_aps' .. id, actor, parent
        noiseActors[id] = actor
        TASK.wait()
        TASK.wait()
        dummy:Destroy()

        local body = "local st=game:GetService('SharedTableRegistry'):GetSharedTable('" .. name .. "')\n"
            .. "local inc=SharedTable.increment\n"
            .. "local lane=" .. (40 + id) .. "\n"
            .. "if st[lane]==nil then st[lane]=1 end\n"
            .. "while st and st[4]~=1 do\n"
            .. " local generation=st[3] or 0\n"
            .. " if generation~=0 then\n"
            .. "  st[" .. (32 + id) .. "]=generation\n"
            .. " else\n"
            .. "  local order=inc(st,0,1)\n"
            .. "  inc(st,lane,(order*69621+" .. id .. "*48271+lane*1103515245)%2147483647+1)\n"
            .. " end\n"
            .. " task.wait(0.05)\n"
            .. "end\n"
        TASK.defer(function()
            local launched, launchError = PCALL(function() ROA(actor, body) end)
            if not launched then
                sharedTable.error = 'actor_noise_launch:' .. tostring(launchError)
                sharedTable.done = -1
            end
        end)
    end

    local stopped = false
    local loopThread
    local stopSession
    stopSession = function()
        if stopped then return end
        stopped = true
        sharedTable[4] = 1
        for _ = 1, 60 do
            if sharedTable.cleaned == 1 then break end
            TASK.wait()
        end
        if sharedTable.cleaned ~= 1 and loopThread and TYPE(TASK.cancel) == 'function' then
            PCALL(TASK.cancel, loopThread)
            sharedTable.cleaned = 1
        end
        cleanup(registry, name, noiseActors)
        PCALL(function()
            if environment[sessionSlot] == stopSession then environment[sessionSlot] = nil end
        end)
    end
    PCALL(function() environment[sessionSlot] = stopSession end)

    loopThread = TASK.defer(function()
        local launched, launchError = PCALL(function()
        local st = sharedTable
        local inc = SharedTable.increment
        local byte, sub, concat, floor, valueType = string.byte, string.sub, table.concat, math.floor, type
        local shared, require = shared, require
        local MOD = 2147483647

        local function hb(n)
            local chars = '0123456789abcdef'
            local high = floor(n / 16)
            return sub(chars, high + 1, high + 1) .. sub(chars, n - high * 16 + 1, n - high * 16 + 1)
        end

        local function h32(n)
            local out = {}
            n = n % 4294967296
            for _ = 1, 4 do
                local quotient = floor(n / 256)
                out[#out + 1] = hb(n - quotient * 256)
                n = quotient
            end
            return concat(out)
        end

        local function hexValue(char)
            local value = byte(char)
            if value >= 48 and value <= 57 then return value - 48 end
            if value >= 65 and value <= 70 then return value - 55 end
            if value >= 97 and value <= 102 then return value - 87 end
        end

        local function xorByte(left, right)
            local result, place = 0, 1
            for _ = 1, 8 do
                if left % 2 ~= right % 2 then result += place end
                left, right, place = floor(left / 2), floor(right / 2), place * 2
            end
            return result
        end

        local function sum(source)
            local hash = 2166136261 % MOD
            for index = 1, #source do
                hash = (hash * 65599 + byte(source, index)) % MOD
            end
            return hash .. ''
        end

        local function seed(source)
            local hash = 1315423911 % MOD
            for index = 1, #source do
                hash = (hash * 65537 + byte(source, index) + (index - 1) * 97) % MOD
            end
            return hash == 0 and 1 or hash
        end

        local function cryptHex(hex, key)
            if valueType(hex) ~= 'string' or #hex % 2 ~= 0 then return nil end
            local state, out = seed(key), {}
            for index = 1, #hex, 2 do
                local high, low = hexValue(sub(hex, index, index)), hexValue(sub(hex, index + 1, index + 1))
                if high == nil or low == nil then return nil end
                local byteIndex = floor((index + 1) / 2)
                state = (state * 48271 + byteIndex * 69621 + 12345) % MOD
                out[#out + 1] = hb(xorByte(high * 16 + low, state % 256))
            end
            return concat(out)
        end

        local function die(code)
            if st then
                st.error = code or 'actor_auth_failed'
                st.done = -1
            end
            error(code or 'actor_auth_failed', 0)
        end

        if not st then return end
        local responseKey = (st.nonce or '') .. '|' .. (st.rng or '') .. '|' .. (st.guard or '')
            .. '|' .. (st.salt or '') .. '|' .. (st.releaseId or '')
        local master, payloadStarted = nil, false

        -- Authentication, payload initialization, and the lifetime heartbeat share
        -- one loop guarded by live Actor lanes. There is no post-auth continuation.
        while st and st[4] ~= 1 do
            inc(st, 17, 1)
            local generation = st[17] or 0
            if generation == 0 then die('actor_generation_checkpoint') end
            st[3] = generation

            for _ = 1, 120 do
                if st[33] == generation and st[34] == generation and st[35] == generation then break end
                task.wait()
            end
            if st[33] ~= generation or st[34] ~= generation or st[35] ~= generation then
                die('actor_lane_checkpoint')
            end

            local marker = game:GetService('HttpService'):GenerateGUID(false):gsub('%W', '')
            local before = st[0] or 0
            inc(st, 16, 1)
            local sequence = st[16] or 0
            st.marker = marker
            task.wait()

            if st.marker ~= marker
                or st[33] ~= generation
                or st[34] ~= generation
                or st[35] ~= generation then
                die('actor_stack_checkpoint')
            end
            st.marker = nil
            st[3] = 0

            local cycleGuard = marker .. h32(before) .. h32(sequence) .. h32(st[0] or 0)
            master = master or cryptHex(st.blob or '', responseKey)
            if not master or sum(master .. '|' .. responseKey) ~= st.keyCheck then
                die('actor_response_check')
            end
            if #master < 16 or #cycleGuard < 16 then die('actor_material_short') end
            if not payloadStarted then st.stage = 'auth_ready' end

            if not payloadStarted then
                st.stage = 'runtime_start'
                local baseRuntime = valueType(shared) == 'table' and shared.vape or nil
                if valueType(baseRuntime) ~= 'table' or valueType(baseRuntime.Libraries) ~= 'table' then
                    die('actor_runtime_unavailable')
                end
                st.stage = 'payload_start'

                local releaseKey, releaseError = bvUnwrapReleaseKey(master, st, sealedPayload.releaseId)
                if not releaseKey then die(releaseError or 'payload_key_unwrap') end
                local payloadChunk, openError = bvOpenSealedPayload(sealedPayload, releaseKey, LOADSTRING)
                releaseKey = nil
                if not payloadChunk then die(openError or 'sealed_payload_open') end
                local payloadResult = payloadChunk(forwardedCredential)
                payloadChunk = nil
                if payloadResult == false then die('sealed_payload_rejected') end

                payloadStarted = true
                st.stage = 'ready'
                st.ticket = sum(master .. '|' .. cycleGuard .. '|' .. responseKey)
                st.done = 1
            else
                st.heartbeat = sum(master .. '|' .. cycleGuard .. '|' .. responseKey)
                inc(st, 18, 1)
            end

            task.wait(0.2)
        end
        end)
        if not launched then
            if not sharedTable.error then
                if sharedTable.stage == 'payload_start' then
                    sharedTable.error = 'actor_payload_failed'
                    sharedTable.payloadError = tostring(launchError)
                else
                    sharedTable.error = 'protected_loop_failed:' .. tostring(launchError)
                end
            end
            if sharedTable.done == nil then sharedTable.done = -1 end
        end
        sharedTable.cleaned = 1
    end)

    local deadline = CLOCK() + 30
    repeat
        if sharedTable.done ~= nil then break end
        TASK.wait()
    until CLOCK() >= deadline

    if sharedTable.done == nil then
        sharedTable.error = 'actor_timeout:' .. tostring(sharedTable.stage or 'unknown')
    elseif sharedTable.done == 1
        and (TYPE(sharedTable.ticket) ~= 'string' or #sharedTable.ticket <= 8) then
        sharedTable.error = 'actor_ticket_invalid'
    end

    local ok = sharedTable.done == 1
        and TYPE(sharedTable.ticket) == 'string'
        and #sharedTable.ticket > 8
    if not ok then
        local actorError = sharedTable.error or 'protected_actor_failed'
        PRINT('[simpleauth]', actorError)
        WARN('[simpleauth]', actorError)
        if sharedTable.payloadError then
            local payloadError = S_SUB(tostring(sharedTable.payloadError), 1, 240)
            PRINT('[simpleauth]', payloadError)
            WARN('[simpleauth]', payloadError)
        end
        stopSession()
        return false
    end

    return true
end)(forwardedCredential)